const config = $input.first().json;
const feeds = config.rssFeeds;
return feeds.map(feed => ({
  json: {
    feedUrl: feed.url,
    feedSource: feed.source,
    feedTier: feed.tier
  }
}));

const items = $input.all();
return items.map(item => {
  const feedSource = $('Loop Over Feeds').item.json.feedSource || 'Unknown';
  const feedTier = $('Loop Over Feeds').item.json.feedTier || 3;
  return {
    json: {
      title: item.json.title || '',
      link: item.json.link || '',
      pubDate: item.json.pubDate || item.json.isoDate || '',
      description: (item.json.contentSnippet || item.json.content || item.json.summary || '').slice(0, 400),
      sourceName: feedSource,
      tier: feedTier
    }
  };
});

const staticData = $getWorkflowStaticData('global');
const config = $('📋 RSS Feed Config1').first().json;
const currentRunId = config.runId;

if (staticData.lastRunId !== currentRunId) {
  staticData.collected = [];
  staticData.lastRunId = currentRunId;
  staticData.feedCount = 0;
}

const totalFeeds = config.rssFeeds.length;

const newItems = $input.all().map(i => i.json).filter(a => a.title && a.link);
staticData.collected.push(...newItems);
staticData.feedCount = (staticData.feedCount || 0) + 1;

const allFeedsProcessed = staticData.feedCount >= totalFeeds;

if (!allFeedsProcessed) {
  return [{ json: { waiting: true, feedsProcessed: staticData.feedCount, totalFeeds } }];
}

const freshnessMs = (config.freshnessHours || 24) * 60 * 60 * 1000;
const cutoff = Date.now() - freshnessMs;
const maxStories = config.maxStoriesInDigest || 5;
const bannedWords = ['sponsored', 'advertisement', 'partner content', 'paid post'];

const valid = staticData.collected.filter(a => {
  if (!a.title || !a.link) return false;
  const pub = a.pubDate ? new Date(a.pubDate).getTime() : 0;
  if (pub && pub < cutoff) return false;
  const titleLower = a.title.toLowerCase();
  if (bannedWords.some(w => titleLower.includes(w))) return false;
  return true;
});

const seenLinks = new Set();
const deduped = valid.filter(a => {
  if (seenLinks.has(a.link)) return false;
  seenLinks.add(a.link);
  return true;
});

const scored = deduped.map(a => {
  let score = 0;
  if (a.tier === 1) score += 3;
  else if (a.tier === 2) score += 2;
  else score += 1;

  const age = a.pubDate ? Date.now() - new Date(a.pubDate).getTime() : 999999999;
  const hours = age / (1000 * 60 * 60);
  if (hours <= 6) score += 3;
  else if (hours <= 12) score += 2;
  else if (hours <= 18) score += 1;

  const titleLower = (a.title || '').toLowerCase();
  const keywords = [
    'fed', 'federal reserve', 'inflation', 'cpi', 'ppi', 'jobs', 'payrolls',
    'earnings', 'guidance', 'revenue', 'profit', 'margin', 'forecast',
    'stocks', 'shares', 'bond', 'bonds', 'yield', 'treasury', 'oil', 'gold',
    'crypto', 'bitcoin', 'merger', 'acquisition', 'ipo', 'tariff', 'rate cut',
    'rate hike', 'downgrade', 'upgrade', 'beats', 'misses', 'announce'
  ];
  keywords.forEach(k => { if (titleLower.includes(k)) score += 1; });

  return { ...a, score };
});

const seenTitles = new Set();
const topStories = scored
  .filter(a => {
    const key = a.title.toLowerCase().slice(0, 40);
    if (seenTitles.has(key)) return false;
    seenTitles.add(key);
    return true;
  })
  .sort((a, b) => b.score - a.score)
  .slice(0, maxStories);

staticData.collected = [];
staticData.feedCount = 0;

if (topStories.length === 0) {
  return [{ json: { topStories: [], empty: true, totalCollected: deduped.length } }];
}

return [{ json: { topStories, totalCollected: deduped.length } }];

const stories = $input.first().json.topStories;

const userContent = 'Write a daily finance digest from these top ' +
  stories.length + ' stories:

' +
  stories.map((s, i) => {
    const title = (s.title || '').replace(/[
]/g, ' ').trim();
    const source = (s.sourceName || '').trim();
    const published = (s.pubDate || '').trim();
    const summary = (s.description || '').replace(/[
]/g, ' ').trim().slice(0, 300);
    const link = (s.link || '').trim();
    return (i + 1) + '. Title: ' + title +
      '
Source: ' + source +
      '
Published: ' + published +
      '
Summary: ' + summary +
      '
Link: ' + link;
  }).join('

');

const systemContent = 'You write a daily finance news digest for investors and operators. Write a sharp, direct digest with one clear insight per story. Format exactly like this in plain text:

1. [Story Title]
[2-3 sentence summary. What happened, why it matters, one sharp insight.]
Source: [Source Name]
Link: [Article URL]

2. [Story Title]
[2-3 sentence summary.]
Source: [Source Name]
Link: [Article URL]

3. [Story Title]
[2-3 sentence summary.]
Source: [Source Name]
Link: [Article URL]

4. [Story Title]
[2-3 sentence summary.]
Source: [Source Name]
Link: [Article URL]

5. [Story Title]
[2-3 sentence summary.]
Source: [Source Name]
Link: [Article URL]

Today's Signal: [One sharp sentence about the overall market or business theme]

Rules: No em dashes. No hype words. Use plain text only. Each summary max 50 words. Never use HTML tags.';

const payload = {
  model: 'mistralai/mistral-large-3-675b-instruct-2512',
  max_tokens: 1500,
  temperature: 0.7,
  top_p: 0.9,
  messages: [
    { role: 'system', content: systemContent },
    { role: 'user', content: userContent }
  ]
};

return [{
  json: {
    nimPayload: JSON.stringify(payload),
    topStories: stories,
    totalCollected: $input.first().json.totalCollected
  }
}];

const rawDigest = $input.first().json.digestText || 'No digest available';
const chatId = $('📋 RSS Feed Config1').first().json.telegramChatId;
const feedCount = $('📋 RSS Feed Config1').first().json.rssFeeds.length;

// Edit header and footer here if you want to rebrand the digest
const header = 'DAILY FINANCE DIGEST\n' +
               'Your signal in the financial noise\n' +
               '─────────────────────────\n\n';

const footer = '\n─────────────────────────\n' +
               `Today\'s digest curated from ${feedCount} finance feeds.\n` +
               'Built by Cordexa Technologies\n' +
               'https://cordexa.tech';

const digestText = header + rawDigest + footer;

const payload = {
  chat_id: chatId,
  text: digestText,
  disable_web_page_preview: true
};

return [{
  json: {
    telegramPayload: JSON.stringify(payload),
    digestText,
    topStories: $input.first().json.topStories,
    totalCollected: $input.first().json.totalCollected
  }
}];
